def add(a, b):
    """Return the sum of a and b."""
    return a + b  # FIXED: using addition instead of subtraction

import pytest
from buggy import add


def test_add_positive():
    assert add(2, 3) == 5


def test_add_negative():
    assert add(-1, -2) == -3


def test_add_mixed():
    assert add(5, -3) == 2


def test_add_zero():
    assert add(0, 0) == 0
    assert add(7, 0) == 7
    assert add(0, 4) == 4
